#!/usr/bin/env node
/**
 * seed-airports.mjs
 *
 * Seeds the Airport model in DynamoDB via the Amplify Data API.
 * Reads airports.full.json (generated by parse-nasr.mjs) and upserts
 * all records in batches.
 *
 * Prerequisites:
 *   1. npm run parse-nasr         — generate src/data/airports.full.json
 *   2. npx ampx sandbox           — local sandbox must be running (or deployed)
 *   3. amplify_outputs.json       — must exist (generated by sandbox/deploy)
 *
 * Usage:
 *   node scripts/seed-airports.mjs
 *   npm run seed-airports
 *
 * The script uses the API key auth mode so it doesn't need a logged-in user.
 * We'll temporarily add API key auth to the airport model for seeding,
 * then remove it after.
 */

import fs from "fs";
import path from "path";
import { fileURLToPath } from "url";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const args = process.argv.slice(2);
const DATA_FILE = args[0] ?? path.join(__dirname, "data", "airports.full.json");
const OUTPUTS = args[1] ?? path.join(__dirname, "..", "amplify_outputs.json");

// ── Validate inputs ───────────────────────────────────────────────────────────

if (!fs.existsSync(DATA_FILE)) {
  console.error(
    `\n❌  airports.full.json not found at ${DATA_FILE}\n    Run: npm run parse-nasr\n`,
  );
  process.exit(1);
}

if (!fs.existsSync(OUTPUTS)) {
  console.error(`\n❌  amplify_outputs.json not found.`);
  console.error(`    Run: npx ampx sandbox   (and wait for it to finish)\n`);
  process.exit(1);
}

const outputs = JSON.parse(fs.readFileSync(OUTPUTS, "utf8"));
const airports = JSON.parse(fs.readFileSync(DATA_FILE, "utf8"));

// ── Validate outputs has what we need ────────────────────────────────────────

const apiUrl = outputs?.data?.url;
const apiKey = outputs?.data?.api_key;
const apiRegion = outputs?.data?.aws_region ?? "us-east-1";

if (!apiUrl) {
  console.error(`\n❌  No data.url found in amplify_outputs.json`);
  console.error(
    `    Make sure the sandbox/deploy has completed successfully.\n`,
  );
  process.exit(1);
}

if (!apiKey) {
  console.error(`\n❌  No data.api_key found in amplify_outputs.json`);
  console.error(
    `    The Airport model needs API key auth enabled for seeding.`,
  );
  console.error(`    See instructions in this script's header comment.\n`);
  process.exit(1);
}

console.log(`\n🌐  API endpoint: ${apiUrl}`);
console.log(`📦  Airports to seed: ${airports.length.toLocaleString()}\n`);

// ── GraphQL helpers ───────────────────────────────────────────────────────────

const CREATE_AIRPORT = /* GraphQL */ `
  mutation CreateAirport($input: CreateAirportInput!) {
    createAirport(input: $input) {
      id
      icaoId
      faaId
    }
  }
`;

async function gql(query, variables) {
  const res = await fetch(apiUrl, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      "x-api-key": apiKey,
    },
    body: JSON.stringify({ query, variables }),
  });
  return res.json();
}

// ── Seed in batches ───────────────────────────────────────────────────────────

const BATCH = 25; // concurrent mutations per batch
const DELAY_MS = 100; // ms between batches to avoid throttling

let created = 0;
let failed = 0;
const errors = [];

const start = Date.now();

for (let i = 0; i < airports.length; i += BATCH) {
  const batch = airports.slice(i, i + BATCH);

  await Promise.all(
    batch.map(async (airport) => {
      // Strip null values — AppSync rejects explicit nulls on non-nullable fields
      const input = Object.fromEntries(
        Object.entries(airport).filter(
          ([, v]) => v !== null && v !== undefined,
        ),
      );

      const result = await gql(CREATE_AIRPORT, { input });

      if (result.errors) {
        // Ignore duplicate errors (already seeded)
        const isDupe = result.errors.some(
          (e) =>
            e.message?.includes("ConditionalCheckFailedException") ||
            e.message?.includes("already exists"),
        );
        if (!isDupe) {
          failed++;
          errors.push({ icaoId: airport.icaoId, errors: result.errors });
        }
      } else {
        created++;
      }
    }),
  );

  // Progress
  const pct = Math.round(((i + batch.length) / airports.length) * 100);
  process.stdout.write(
    `\r  Progress: ${pct}%  (${created} created, ${failed} failed)`,
  );

  if (i + BATCH < airports.length) {
    await new Promise((r) => setTimeout(r, DELAY_MS));
  }
}

const elapsed = ((Date.now() - start) / 1000).toFixed(1);

console.log(`\n\n✅  Seeding complete in ${elapsed}s`);
console.log(`    Created: ${created}`);
console.log(`    Failed:  ${failed}`);

if (errors.length > 0) {
  console.log(`\n⚠️   First 5 errors:`);
  errors
    .slice(0, 5)
    .forEach((e) => console.log(`    ${e.icaoId}:`, JSON.stringify(e.errors)));
}

console.log();
